29	/**
30	 * Maintains an ordered collection of {@link ExitCodeGenerator} instances and allows the
31	 * final exit code to be calculated. Generators are ordered by {@link Order @Order} and
32	 * {@link Ordered}.
33	 *
34	 * @author Dave Syer
35	 * @author Phillip Webb
36	 * @author GenKui Du
37	 * @see #getExitCode()
38	 * @see ExitCodeGenerator
39	 */
40	class ExitCodeGenerators implements Iterable<ExitCodeGenerator> {
41	
42		private final List<ExitCodeGenerator> generators = new ArrayList<>();
43	
44		void addAll(Throwable exception, ExitCodeExceptionMapper... mappers) {
45			Assert.notNull(exception, "'exception' must not be null");
46			Assert.notNull(mappers, "'mappers' must not be null");
47			addAll(exception, Arrays.asList(mappers));
48		}
49	
50		void addAll(Throwable exception, Iterable<? extends ExitCodeExceptionMapper> mappers) {
51			Assert.notNull(exception, "'exception' must not be null");
52			Assert.notNull(mappers, "'mappers' must not be null");
53			for (ExitCodeExceptionMapper mapper : mappers) {
54				add(exception, mapper);
55			}
56		}
57	
58		void add(Throwable exception, ExitCodeExceptionMapper mapper) {
59			Assert.notNull(exception, "'exception' must not be null");
60			Assert.notNull(mapper, "'mapper' must not be null");
61			add(new MappedExitCodeGenerator(exception, mapper));
62		}
63	
64		void addAll(ExitCodeGenerator... generators) {
65			Assert.notNull(generators, "'generators' must not be null");
66			addAll(Arrays.asList(generators));
67		}
68	
69		void addAll(Iterable<? extends ExitCodeGenerator> generators) {
70			Assert.notNull(generators, "'generators' must not be null");
71			for (ExitCodeGenerator generator : generators) {
72				add(generator);
73			}
74		}
75	
76		void add(ExitCodeGenerator generator) {
77			Assert.notNull(generator, "'generator' must not be null");
78			this.generators.add(generator);
79			AnnotationAwareOrderComparator.sort(this.generators);
80		}
81	
82		@Override
83		public Iterator<ExitCodeGenerator> iterator() {
84			return this.generators.iterator();
85		}
86	
87		/**
88		 * Get the final exit code that should be returned. The final exit code is the first
89		 * non-zero exit code that is {@link ExitCodeGenerator#getExitCode generated}.
90		 * @return the final exit code.
91		 */
92		int getExitCode() {
93			int exitCode = 0;
94			for (ExitCodeGenerator generator : this.generators) {
95				try {
96					int value = generator.getExitCode();
97					if (value != 0) {
98						exitCode = value;
99						break;
100					}
101				}
102				catch (Exception ex) {
103					exitCode = 1;
104					ex.printStackTrace();
105				}
106			}
107			return exitCode;
108		}
109	
110		/**
111		 * Adapts an {@link ExitCodeExceptionMapper} to an {@link ExitCodeGenerator}.
112		 */
113		private static class MappedExitCodeGenerator implements ExitCodeGenerator {
114	
115			private final Throwable exception;
116	
117			private final ExitCodeExceptionMapper mapper;
118	
119			MappedExitCodeGenerator(Throwable exception, ExitCodeExceptionMapper mapper) {
120				this.exception = exception;
121				this.mapper = mapper;
122			}
123	
124			@Override
125			public int getExitCode() {
126				return this.mapper.getExitCode(this.exception);
127			}
128	
129		}
130	
131	}
