29	/**
30	 * {@link UncaughtExceptionHandler} to suppress handling already logged exceptions and
31	 * dealing with system exit.
32	 *
33	 * @author Phillip Webb
34	 */
35	class SpringBootExceptionHandler implements UncaughtExceptionHandler {
36	
37		private static final Set<String> LOG_CONFIGURATION_MESSAGES;
38	
39		static {
40			Set<String> messages = new HashSet<>();
41			messages.add("Logback configuration error detected");
42			LOG_CONFIGURATION_MESSAGES = Collections.unmodifiableSet(messages);
43		}
44	
45		private static final LoggedExceptionHandlerThreadLocal handler = new LoggedExceptionHandlerThreadLocal();
46	
47		private final @Nullable UncaughtExceptionHandler parent;
48	
49		private final List<Throwable> loggedExceptions = new ArrayList<>();
50	
51		private int exitCode;
52	
53		SpringBootExceptionHandler(@Nullable UncaughtExceptionHandler parent) {
54			this.parent = parent;
55		}
56	
57		void registerLoggedException(Throwable exception) {
58			this.loggedExceptions.add(exception);
59		}
60	
61		void registerExitCode(int exitCode) {
62			this.exitCode = exitCode;
63		}
64	
65		@Override
66		public void uncaughtException(Thread thread, Throwable ex) {
67			try {
68				if (isPassedToParent(ex) && this.parent != null) {
69					this.parent.uncaughtException(thread, ex);
70				}
71			}
72			finally {
73				this.loggedExceptions.clear();
74				if (this.exitCode != 0) {
75					System.exit(this.exitCode);
76				}
77			}
78		}
79	
80		private boolean isPassedToParent(Throwable ex) {
81			return isLogConfigurationMessage(ex) || !isRegistered(ex);
82		}
83	
84		/**
85		 * Check if the exception is a log configuration message, i.e. the log call might not
86		 * have actually output anything.
87		 * @param ex the source exception
88		 * @return {@code true} if the exception contains a log configuration message
89		 */
90		private boolean isLogConfigurationMessage(@Nullable Throwable ex) {
91			if (ex == null) {
92				return false;
93			}
94			if (ex instanceof InvocationTargetException) {
95				return isLogConfigurationMessage(ex.getCause());
96			}
97			String message = ex.getMessage();
98			if (message != null) {
99				for (String candidate : LOG_CONFIGURATION_MESSAGES) {
100					if (message.contains(candidate)) {
101						return true;
102					}
103				}
104			}
105			return false;
106		}
107	
108		private boolean isRegistered(@Nullable Throwable ex) {
109			if (ex == null) {
110				return false;
111			}
112			if (this.loggedExceptions.contains(ex)) {
113				return true;
114			}
115			if (ex instanceof InvocationTargetException) {
116				return isRegistered(ex.getCause());
117			}
118			return false;
119		}
120	
121		static SpringBootExceptionHandler forCurrentThread() {
122			return handler.get();
123		}
124	
125		/**
126		 * Thread local used to attach and track handlers.
127		 */
128		private static final class LoggedExceptionHandlerThreadLocal extends ThreadLocal<SpringBootExceptionHandler> {
129	
130			@Override
131			protected SpringBootExceptionHandler initialValue() {
132				SpringBootExceptionHandler handler = new SpringBootExceptionHandler(
133						Thread.currentThread().getUncaughtExceptionHandler());
134				Thread.currentThread().setUncaughtExceptionHandler(handler);
135				return handler;
136			}
137	
138		}
139	
140	}
