803		private RuntimeException handleRunFailure(@Nullable ConfigurableApplicationContext context, Throwable exception,
804				@Nullable SpringApplicationRunListeners listeners) {
805			if (exception instanceof AbandonedRunException abandonedRunException) {
806				return abandonedRunException;
807			}
808			try {
809				try {
810					handleExitCode(context, exception);
811					if (listeners != null) {
812						listeners.failed(context, exception);
813					}
814				}
815				finally {
816					reportFailure(getExceptionReporters(context), exception);
817					if (context != null) {
818						context.close();
819						shutdownHook.deregisterFailedApplicationContext(context);
820					}
821				}
822			}
823			catch (Exception ex) {
824				logger.warn("Unable to close ApplicationContext", ex);
825			}
826			return (exception instanceof RuntimeException runtimeException) ? runtimeException
827					: new IllegalStateException(exception);
